import{_ as o,o as t,c as a,ag as n}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Set Up Your Company","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/company-setup.md","filePath":"getting-started/company-setup.md"}'),i={name:"getting-started/company-setup.md"};function r(s,e,l,d,c,u){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="set-up-your-company" tabindex="-1">Set Up Your Company <a class="header-anchor" href="#set-up-your-company" aria-label="Permalink to &quot;Set Up Your Company&quot;">​</a></h1><p>Before you can send invoices, you need to configure your company information. This data appears on your invoices, quotes, and other documents.</p><h2 id="company-information" tabindex="-1">Company information <a class="header-anchor" href="#company-information" aria-label="Permalink to &quot;Company information&quot;">​</a></h2><p>Navigate to <strong>Company</strong> in the sidebar to access your company settings.</p><h3 id="required-fields" tabindex="-1">Required fields <a class="header-anchor" href="#required-fields" aria-label="Permalink to &quot;Required fields&quot;">​</a></h3><p>These fields are needed to send invoices:</p><ul><li><strong>Company name</strong> — Your registered business name</li><li><strong>Address</strong> — Street, postal code, and city (address autocomplete is available)</li><li><strong>Email</strong> — Your business contact email</li></ul><h3 id="recommended-fields" tabindex="-1">Recommended fields <a class="header-anchor" href="#recommended-fields" aria-label="Permalink to &quot;Recommended fields&quot;">​</a></h3><p>These are strongly recommended for professional invoices and legal compliance:</p><ul><li><strong>VAT number</strong> — Your VAT registration number (e.g., NL123456789B01)</li><li><strong>Chamber of Commerce / Registration number</strong> — Your business registration ID</li><li><strong>IBAN</strong> — Your bank account number where customers should pay</li><li><strong>Phone number</strong> — Business contact phone</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In many countries, VAT number and registration number are legally required on invoices. Make sure these are filled in before sending your first invoice.</p></div><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><h3 id="company-logo" tabindex="-1">Company logo <a class="header-anchor" href="#company-logo" aria-label="Permalink to &quot;Company logo&quot;">​</a></h3><p>Upload your company logo to have it appear on:</p><ul><li>Invoices and quotes (PDF)</li><li>Email communications</li><li>Your public business page</li><li>The customer payment portal</li></ul><p>Supported formats: PNG, JPG, SVG. For best results, use a high-resolution image with a transparent background.</p><h3 id="color-scheme" tabindex="-1">Color scheme <a class="header-anchor" href="#color-scheme" aria-label="Permalink to &quot;Color scheme&quot;">​</a></h3><p>Customize the accent color used on your invoices and documents to match your brand identity.</p><h2 id="financial-defaults" tabindex="-1">Financial defaults <a class="header-anchor" href="#financial-defaults" aria-label="Permalink to &quot;Financial defaults&quot;">​</a></h2><p>Set up defaults that apply to new invoices and quotes:</p><ul><li><strong>Currency</strong> — Your default currency (EUR by default)</li><li><strong>Payment terms</strong> — Default number of days until an invoice is due (e.g., 14 or 30 days)</li><li><strong>Invoice numbering</strong> — Customize the format of your invoice numbers <ul><li>Prefix (e.g., <code>INV-</code> or <code>2024-</code>)</li><li>Starting number</li><li>Auto-increment</li></ul></li></ul><h3 id="invoice-numbering-examples" tabindex="-1">Invoice numbering examples <a class="header-anchor" href="#invoice-numbering-examples" aria-label="Permalink to &quot;Invoice numbering examples&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Format</th><th>Example</th></tr></thead><tbody><tr><td>Simple</td><td><code>001</code>, <code>002</code>, <code>003</code></td></tr><tr><td>With prefix</td><td><code>INV-001</code>, <code>INV-002</code></td></tr><tr><td>Year-based</td><td><code>2024-001</code>, <code>2024-002</code></td></tr></tbody></table><p>The numbering resets options and format can be adjusted at any time. Existing invoice numbers are never changed.</p><h2 id="pdf-template" tabindex="-1">PDF template <a class="header-anchor" href="#pdf-template" aria-label="Permalink to &quot;PDF template&quot;">​</a></h2><p>MyCompanyDesk generates professional PDF invoices automatically. You can customize the layout using the <strong>PDF Editor</strong>:</p><ul><li>Adjust field positions and visibility</li><li>Choose which information to display</li><li>Customize fonts and sizing</li><li>Preview changes in real-time with a sample invoice</li></ul><p>Access the PDF editor from <strong>Company &gt; PDF Editor</strong> or from the branding section.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>PDF customization beyond basic settings requires the <strong>Pro</strong> plan or higher.</p></div><h2 id="features-toggle" tabindex="-1">Features toggle <a class="header-anchor" href="#features-toggle" aria-label="Permalink to &quot;Features toggle&quot;">​</a></h2><p>MyCompanyDesk has optional modules that you can enable or disable depending on your business needs:</p><ul><li><strong>Objects / Assets</strong> — For rental property and asset management</li><li><strong>Contracts</strong> — For recurring service or rental contracts</li><li><strong>Projects</strong> — For project-based work and time tracking</li><li><strong>Quotes</strong> — For sending quotations</li><li><strong>Reverse charge</strong> — For intra-EU B2B transactions</li><li><strong>AI suggestions</strong> — For smart categorization and recommendations</li><li><strong>Receipt scanning</strong> — For OCR-based expense entry</li><li><strong>Text check</strong> — For grammar and spelling in your documents</li></ul><p>Disabling a module hides it from the navigation, keeping your workspace clean and focused.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Your company is set up. Time to <a href="/getting-started/first-invoice">create your first invoice</a>.</p>',35)])])}const g=o(i,[["render",r]]);export{p as __pageData,g as default};
